def _round_currency(amount: Decimal) -> Decimal:
    """Round to 2 decimal places using banker's rounding."""
    return amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


# ============================================================
# STEP 1: Validate Cart Items
# ============================================================
def step_validate_cart(state: CheckoutState) -> CheckoutState:
    """
    Validates cart items against the product catalog.
    Checks: non-empty cart, product existence, price integrity,
    stock availability, quantity limits, and user status.
    """
    state = state.add_audit("Step 1: Cart validation started")

    # Validate user
    if state.user is None:
        raise ValidationError("User is required for checkout")
    if not state.user.is_active:
        raise ValidationError("User account is not active")
    if not state.user.is_verified:
        raise ValidationError("User account is not verified")

    # Validate cart is not empty
    if not state.cart_items:
        raise ValidationError("Cart is empty")

    # Enforce maximum cart size to prevent abuse
    MAX_CART_ITEMS = 50
    if len(state.cart_items) > MAX_CART_ITEMS:
        raise ValidationError(f"Cart exceeds maximum of {MAX_CART_ITEMS} line items")

    seen_product_ids = set()
    subtotal = Decimal("0")

    for item in state.cart_items:
        if not isinstance(item, CartItem):
            raise ValidationError(f"Invalid cart item type: {type(item)}")

        # Check for duplicate product IDs (prevent double-counting exploits)
        if item.product_id in seen_product_ids:
            raise ValidationError(
                f"Duplicate product in cart: {item.product_id}. "
                "Combine quantities into a single line item."
            )
        seen_product_ids.add(item.product_id)

        # Check product exists in catalog
        catalog_entry = PRODUCT_CATALOG.get(item.product_id)
        if catalog_entry is None:
            raise ValidationError(f"Product not found: {item.product_id}")

        # CRITICAL: Validate price matches catalog (prevent price tampering)
        catalog_price = catalog_entry["price"]
        if item.price != catalog_price:
            raise ValidationError(
                f"Price mismatch for {item.product_id}: "
                f"submitted {item.price}, catalog {catalog_price}. "
                "Possible price tampering detected."
            )

        # Check stock availability
        if item.quantity > catalog_entry["in_stock"]:
            raise ValidationError(
                f"Insufficient stock for {item.product_id}: "
                f"requested {item.quantity}, available {catalog_entry['in_stock']}"
            )

        # Check per-order quantity limits
        max_qty = catalog_entry["max_per_order"]
        if item.quantity > max_qty:
            raise ValidationError(
                f"Quantity limit exceeded for {item.product_id}: "
                f"max {max_qty} per order, requested {item.quantity}"
            )

        # Calculate line total using catalog price (not submitted price)
        line_total = _round_currency(catalog_price * item.quantity)
        subtotal += line_total

    # Validate subtotal is positive
    if subtotal <= Decimal("0"):
        raise ValidationError("Cart subtotal must be positive")

    # Enforce maximum order amount
    MAX_ORDER_AMOUNT = Decimal("10000.00")
    if subtotal > MAX_ORDER_AMOUNT:
        raise ValidationError(f"Order exceeds maximum amount of {MAX_ORDER_AMOUNT}")

    state = state.with_update(
        status=OrderStatus.VALIDATED,
        validated_subtotal=subtotal,
    )
    state = state.add_audit(f"Step 1: Cart validated. Subtotal: ${subtotal}")
    return state


