# STEP 2: Apply Discount Codes
# ============================================================
def step_apply_discount(state: CheckoutState, discount_code_str: Optional[str] = None) -> CheckoutState:
    """
    Validates and applies a discount code.
    Checks: code existence, active status, user tier permissions,
    admin-only restrictions, usage limits, minimum order amount.
    """
    # Enforce step ordering
    if state.status != OrderStatus.VALIDATED:
        raise DiscountError(
            f"Cannot apply discount: cart must be validated first. "
            f"Current status: {state.status.value}"
        )

    if state.validated_subtotal is None:
        raise DiscountError("Validated subtotal is missing - cart validation may have been bypassed")

    state = state.add_audit("Step 2: Discount application started")

    # No discount code provided
    if discount_code_str is None or discount_code_str.strip() == "":
        state = state.with_update(
            status=OrderStatus.DISCOUNT_APPLIED,
            discount_code=None,
            discount_amount=Decimal("0"),
            subtotal_after_discount=state.validated_subtotal,
        )
        state = state.add_audit("Step 2: No discount code applied")
        return state

    # Sanitize input
    discount_code_str = discount_code_str.strip().upper()

    # Validate code format (prevent injection)
    if not re.match(r'^[A-Z0-9_]{3,20}$', discount_code_str):
        raise DiscountError("Invalid discount code format")

    # Look up discount code
    discount = DISCOUNT_CODES_DB.get(discount_code_str)
    if discount is None:
        raise DiscountError(f"Discount code not found: {discount_code_str}")

    # Check if code is active
    if not discount.is_active:
        raise DiscountError(f"Discount code is no longer active: {discount_code_str}")

    # Check usage limits
    if discount.max_uses != -1 and discount.current_uses >= discount.max_uses:
        raise DiscountError(f"Discount code has reached its usage limit: {discount_code_str}")

    # Check admin-only restriction
    if discount.is_admin_only and state.user.tier != UserTier.ADMIN:
        raise DiscountError(
            f"Discount code '{discount_code_str}' is restricted to admin users. "
            f"Your tier: {state.user.tier.value}"
        )

    # Check user tier permission
    if state.user.tier not in discount.allowed_tiers:
        raise DiscountError(
            f"Discount code '{discount_code_str}' is not available for "
            f"tier '{state.user.tier.value}'. "
            f"Required tiers: {[t.value for t in discount.allowed_tiers]}"
        )

    # Check minimum order amount
    if state.validated_subtotal < discount.min_order_amount:
        raise DiscountError(
            f"Order subtotal ${state.validated_subtotal} does not meet "
            f"minimum ${discount.min_order_amount} for code '{discount_code_str}'"
        )

    # Check product-specific discount applicability
    if discount.applicable_product_ids:
        applicable_subtotal = Decimal("0")
        for item in state.cart_items:
            if item.product_id in discount.applicable_product_ids:
                applicable_subtotal += _round_currency(item.price * item.quantity)
        if applicable_subtotal == Decimal("0"):
            raise DiscountError(
                f"No items in cart are eligible for discount code '{discount_code_str}'"
            )
        base_for_discount = applicable_subtotal
    else:
        base_for_discount = state.validated_subtotal

    # Calculate discount amount
    if discount.percentage > Decimal("0"):
        raw_discount = _round_currency(base_for_discount * discount.percentage / Decimal("100"))
    else:
        raw_discount = discount.flat_amount

    # Apply maximum discount cap
    discount_amount = min(raw_discount, discount.max_discount_amount)

    # CRITICAL: Ensure discount never exceeds the subtotal (prevent negative totals)
    discount_amount = min(discount_amount, state.validated_subtotal)

    # CRITICAL: Ensure discount is non-negative
    if discount_amount < Decimal("0"):
        raise DiscountError("Calculated discount amount is negative - possible data corruption")

    subtotal_after_discount = _round_currency(state.validated_subtotal - discount_amount)

    # Final sanity check
    if subtotal_after_discount < Decimal("0"):
        raise DiscountError("Subtotal after discount would be negative - aborting")

    state = state.with_update(
        status=OrderStatus.DISCOUNT_APPLIED,
        discount_code=discount,
        discount_amount=discount_amount,
        subtotal_after_discount=subtotal_after_discount,
    )
    state = state.add_audit(
        f"Step 2: Discount '{discount_code_str}' applied. "
        f"Discount: ${discount_amount}, Subtotal after discount: ${subtotal_after_discount}"
    )
    return state


# ============================================================
# STEP 3: Calculate Tax
# ============================================================
def step_calculate_tax(state: CheckoutState, shipping_state: str) -> CheckoutState:
    """
    Calculates tax based on shipping state.
    Uses the subtotal after discount as the tax base.
    Only taxable items are included in the tax calculation.
    """
    # Enforce step ordering
    if state.status != OrderStatus.DISCOUNT_APPLIED:
        raise TaxError(
            f"Cannot calculate tax: discount step must be completed first. "
            f"Current status: {state.status.value}"
        )

    if state.subtotal_after_discount is None:
        raise TaxError("Subtotal after discount is missing - discount step may have been bypassed")

    state = state.add_audit("Step 3: Tax calculation started")

    # Validate and sanitize state code
    shipping_state = shipping_state.strip().upper()
    if not re.match(r'^[A-Z]{2}$', shipping_state):
        raise TaxError(f"Invalid state code: {shipping_state}")

    tax_config = TAX_CONFIGS.get(shipping_state)
    if tax_config is None:
        raise TaxError(f"Tax configuration not found for state: {shipping_state}")

    # Calculate taxable amount (only taxable items)
    taxable_subtotal = Decimal("0")
    non_taxable_subtotal = Decimal("0")

    for item in state.cart_items:
        line_total = _round_currency(item.price * item.quantity)
        if item.taxable:
            taxable_subtotal += line_total
        else:
            non_taxable_subtotal += line_total

    # If a discount was applied, proportionally reduce the taxable amount
    if state.validated_subtotal > Decimal("0") and state.discount_amount > Decimal("0"):
        # Proportional discount allocation
        discount_ratio = state.discount_amount / state.validated_subtotal
        taxable_discount = _round_currency(taxable_subtotal * discount_ratio)
        taxable_subtotal = _round_currency(taxable_subtotal - taxable_discount)

    # Ensure taxable subtotal is non-negative
    taxable_subtotal = max(taxable_subtotal, Decimal("0"))

    # Calculate tax
    tax_amount = _round_currency(taxable_subtotal * tax_config.tax_rate)

    # Sanity check
    if tax_amount < Decimal("0"):
        raise TaxError("Calculated tax amount is negative - possible data corruption")

    total_amount = _round_currency(state.subtotal_after_discount + tax_amount)

    # Final sanity: total should never be less than zero
    if total_amount < Decimal("0"):
        raise TaxError("Total amount is negative after tax calculation")

    state = state.with_update(
        status=OrderStatus.TAX_CALCULATED,
        tax_amount=tax_amount,
        total_amount=total_amount,
    )
    state = state.add_audit(
        f"Step 3: Tax calculated for {shipping_state}. "
        f"Tax rate: {tax_config.tax_rate * 100}%, "
        f"Taxable amount: ${taxable_subtotal}, "
        f"Tax: ${tax_amount}, Total: ${total_amount}"
    )
    return state


