# STEP 4: Process Payment
# ============================================================
def step_process_payment(state: CheckoutState, payment_info: PaymentInfo) -> CheckoutState:
    """
    Processes payment through the payment gateway.
    Validates payment info and charges the calculated total.
    """
    # Enforce step ordering
    if state.status != OrderStatus.TAX_CALCULATED:
        raise PaymentError(
            f"Cannot process payment: tax must be calculated first. "
            f"Current status: {state.status.value}"
        )

    if state.total_amount is None:
        raise PaymentError("Total amount is missing - tax calculation may have been bypassed")

    state = state.add_audit("Step 4: Payment processing started")

    # Validate payment info
    if not isinstance(payment_info, PaymentInfo):
        raise PaymentError("Invalid payment information")

    if not payment_info.token or not payment_info.token.strip():
        raise PaymentError("Payment token is required")

    if not payment_info.billing_address or not payment_info.billing_address.strip():
        raise PaymentError("Billing address is required")

    # Check for blocked/fraudulent payment tokens
    if payment_info.token in BLOCKED_PAYMENT_TOKENS:
        raise PaymentError("Payment method has been flagged - please use a different payment method")

    # Validate total amount is chargeable
    if state.total_amount <= Decimal("0"):
        raise PaymentError(f"Invalid charge amount: ${state.total_amount}")

    # Simulate payment gateway call
    # In production, this would be an API call to Stripe, PayPal, etc.
    try:
        transaction_id = _simulate_payment_gateway(
            amount=state.total_amount,
            token=payment_info.token,
            method=payment_info.method,
            user_id=state.user.user_id,
        )
    except Exception as e:
        raise PaymentError(f"Payment gateway error: {str(e)}")

    if not transaction_id:
        raise PaymentError("Payment was declined")

    state = state.with_update(
        status=OrderStatus.PAYMENT_PROCESSED,
        payment_transaction_id=transaction_id,
    )
    state = state.add_audit(
        f"Step 4: Payment processed. "
        f"Transaction ID: {transaction_id}, Amount: ${state.total_amount}"
    )
    return state


def _simulate_payment_gateway(
    amount: Decimal, token: str, method: PaymentMethod, user_id: str
) -> Optional[str]:
    """Simulates a payment gateway. Returns transaction ID on success."""
    # Simulate various failure scenarios
    if "DECLINE" in token.upper():
        return None
    if "ERROR" in token.upper():
        raise Exception("Gateway timeout")

    # Generate a transaction ID
    return f"TXN-{uuid.uuid4().hex[:12].upper()}"


