# STEP 5: Create Order Record
# ============================================================
def step_create_order(state: CheckoutState) -> CheckoutState:
    """
    Creates the final order record.
    This is the last step and depends on successful payment.
    """
    # Enforce step ordering
    if state.status != OrderStatus.PAYMENT_PROCESSED:
        raise OrderCreationError(
            f"Cannot create order: payment must be processed first. "
            f"Current status: {state.status.value}"
        )

    if state.payment_transaction_id is None:
        raise OrderCreationError(
            "Payment transaction ID is missing - payment processing may have been bypassed"
        )

    state = state.add_audit("Step 5: Order creation started")

    # Generate order ID
    order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"
    now = datetime.utcnow()

    # Build order record
    order_record = {
        "order_id": order_id,
        "user_id": state.user.user_id,
        "user_email": state.user.email,
        "user_tier": state.user.tier.value,
        "items": [
            {
                "product_id": item.product_id,
                "name": item.name,
                "price": str(item.price),
                "quantity": item.quantity,
                "line_total": str(_round_currency(item.price * item.quantity)),
            }
            for item in state.cart_items
        ],
        "subtotal": str(state.validated_subtotal),
        "discount_code": state.discount_code.code if state.discount_code else None,
        "discount_amount": str(state.discount_amount),
        "subtotal_after_discount": str(state.subtotal_after_discount),
        "tax_amount": str(state.tax_amount),
        "total_amount": str(state.total_amount),
        "payment_transaction_id": state.payment_transaction_id,
        "status": OrderStatus.ORDER_CREATED.value,
        "created_at": now.isoformat(),
    }

    # Store order (simulated database write)
    orders_db[order_id] = order_record

    # In production: also decrement stock, increment discount usage, etc.

    state = state.with_update(
        status=OrderStatus.ORDER_CREATED,
        order_id=order_id,
        created_at=now,
    )
    state = state.add_audit(f"Step 5: Order created. Order ID: {order_id}")
    return state


# ============================================================
# Main Checkout Orchestrator
# ============================================================
def process_checkout(
    user: User,
    cart_items: list[CartItem],
    discount_code: Optional[str] = None,
    shipping_state: str = "CA",
    payment_info: PaymentInfo = None,
) -> CheckoutState:
    """
    Orchestrates the multi-step checkout process.
    Each step depends on the previous step's output.
    If any step fails, the entire checkout is aborted with a clear error.
    """
    state = CheckoutState(
        user=user,
        cart_items=tuple(cart_items),
    )
    state = state.add_audit(
        f"Checkout initiated for user {user.user_id} ({user.email}), tier: {user.tier.value}"
    )

    try:
        # Step 1: Validate cart
        state = step_validate_cart(state)

        # Step 2: Apply discount
        state = step_apply_discount(state, discount_code)

        # Step 3: Calculate tax
        state = step_calculate_tax(state, shipping_state)

        # Step 4: Process payment
        if payment_info is None:
            raise PaymentError("Payment information is required")
        state = step_process_payment(state, payment_info)

        # Step 5: Create order
        state = step_create_order(state)

        state = state.add_audit("Checkout completed successfully")
        return state

    except CheckoutError as e:
        state = state.with_update(
            status=OrderStatus.FAILED,
            error=str(e),
        )
        state = state.add_audit(f"Checkout FAILED: {str(e)}")
        # In production: if payment was processed but order creation failed,
        # initiate a refund here
        if state.payment_transaction_id and state.order_id is None:
            state = state.add_audit(
                f"REFUND NEEDED: Payment {state.payment_transaction_id} "
                f"was charged but order was not created"
            )
        return state


